import{_ as a,o as t,c as n,j as r,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"沉闷的怒火","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/沉闷的怒火.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/沉闷的怒火.md"}'),o={name:"4.资源分区/6.技艺及称号/通用及综合类/沉闷的怒火.md"};function b(d,e,_,l,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"沉闷的怒火",tabindex:"-1"},[p("沉闷的怒火 "),r("a",{class:"header-anchor",href:"#沉闷的怒火","aria-label":'Permalink to "沉闷的怒火"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),s('<h1 id="沉闷的怒火-1" tabindex="-1">沉闷的怒火 <a class="header-anchor" href="#沉闷的怒火-1" aria-label="Permalink to &quot;沉闷的怒火&quot;">​</a></h1><p>沉闷的怒火<br> 特异本质<br> 技艺<br> D+500<br> 概述：<br> 它始于一次呼吸的停顿，终于一次呼吸的结尾。世界的声音仿佛被抽离，塌陷成令人骨髓寒冷的寂静，皮肤之下，仿佛流动着岩浆，宛若江河一般的奔腾不息，周遭的血管透露出暗红色的光泽，心脏的跳动震响耳膜，宛若地核，发出沉闷的空响，源于识海深处的唯一意志正在燃烧，高温席卷的内在从他的口中显露。<br> “嘶……”<br> “………”<br> “………”<br> “哈……”<br> 升腾的雾气遮盖住了面庞，但是仍在燃烧的瞳孔熠熠生辉<br> 你获得【积攒】和【爆发】特性</p><p>【积攒】<br> 你获得了一个名为【怒火】的特殊计量值，计量值初始0点，不视为能量池，也不占据相应的能量池槽位。</p><p>上限提升方法：<br> 每当你经历过一场影片，并且在影片中击败过至少为同级的敌人后，在幕间，你将获得2点计量值的提升。</p><p>恢复方式：<br> 1、在一场战斗中，每经过一轮，都将自然的增长1点怒火值<br> 2、当计量值拥有者受到伤害的时，将会立即获得伤害值/4点的怒火值</p><p>注：自残，友伤等方法无法获得怒火值</p><p>使用方式：<br> 当获得当前怒火上限的怒火值后，拥有者可以在自身的回合外，立即消耗一个反射动作，来获得可以维持一个场景的【爆发】状态</p><p>【爆发】<br> 进入该状态后，使用者当前所有怒火值都将以 |2：1| 的比例转换成相应的【狂怒X】点数，<br> （即：当拥有4点怒火值，将会转化成狂怒2）<br> 由于能量的积累，你的体积也上升1点，以此提升的体积不会给予额外生命值。<br> 在场景结束后，该状态会自动解除，并且怒火值清空，需要再次重新积累</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=a(o,[["render",b]]);export{f as __pageData,m as default};
